script.text:
      &OutlineEntry;

function active$VoucherFilter$(sender) {sender.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = new Array();
      g._year = f.getItemValue('nam');
      g._period = f.getItemValue('ky');

      var c = $func.trim(f.getItemValue('ma_dc')), u = $func.trim(f.getItemValue('ma_bp_dc')), t = $func.trim(f.getItemValue('loai_dc')), u = $func.trim(f.getItemValue('ma_dvcs'));
      var g1 = $func.trim(f.getItemValue('nh_dc1')), g2 = $func.trim(f.getItemValue('nh_dc2')), g3 = $func.trim(f.getItemValue('nh_dc3'));            

      Array.add(k, {Name: 'nam', Opr: '=', Value: g._year, Type: 'Numeric', Ignore: false});    
      Array.add(k, {Name: 'ky', Opr: '=', Value: g._period, Type: 'Numeric', Ignore: false});

      if (c) Array.add(k, {Name: 'ma_dc', Opr: 'like', Value: c + '%', Type: 'String', Ignore: false});
      if (u) Array.add(k, {Name: 'ma_bp_dc', Opr: 'like', Value: u + '%', Type: 'String', Ignore: false});
      if (t) Array.add(k, {Name: 'loai_dc', Opr: 'like', Value: t + '%', Type: 'String', Ignore: false});
      if (g1) Array.add(k, {Name: 'nh_dc1', Opr: 'like', Value: g1 + '%', Type: 'String', Ignore: false});
      if (g2) Array.add(k, {Name: 'nh_dc2', Opr: 'like', Value: g2 + '%', Type: 'String', Ignore: false});
      if (g3) Array.add(k, {Name: 'nh_dc3', Opr: 'like', Value: g3 + '%', Type: 'String', Ignore: false});      
      if (u) Array.add(k, {Name: 'ma_dvcs', Opr: 'like', Value: u + '%', Type: 'String', Ignore: false});

      g.set_externalKey(k);      
      g._alterTitle = [null, [['%s1', g._period, true], ['%s2', g._year, true]]];
      break;    
    default:
      break;
  }
}
